mapper.select:
SELECT r.`rank` AS `rank`, n.id AS novelId, n.title AS title, n.author AS author, n.category AS category, n.cover_url AS coverUrl, n.novel_url AS novelUrl, n.word_count AS wordCount, n.status AS status, r.view_count AS viewCount, r.rec_count AS recCount, r.crawl_time AS crawlTime FROM v_latest_rank_snapshot r JOIN novel n ON r.novel_id = n.id
r.ranking_type = #{rankingType} AND r.site_id = (SELECT id FROM site WHERE code = #{siteCode})
AND COALESCE(r.category, n.category) = #{category}
AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.author LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.`rank` ASC LIMIT #{offset}, #{size}

SELECT r.`rank` AS `rank`, n.id AS novelId, n.title AS title, s.code AS siteCode, s.name AS siteName, s.color AS color, r.view_count AS viewCount FROM v_latest_rank_snapshot r JOIN novel n ON r.novel_id = n.id JOIN site s ON r.site_id = s.id
r.ranking_type = 'daily'
AND r.category = #{category}
ORDER BY r.view_count DESC LIMIT #{limit}
